const serviceOrder = ['sso','ai','crm','erp','finance','pdv','rpg','omnichannel','admin','wellness','lead-enrichment','customer','intelligence'];
const items = $input.all();
const failed = [];
items.forEach((item, i) => {
  const statusCode = item.json?.statusCode ?? item.json?.code ?? 0;
  const body = item.json?.body ?? item.json;
  const ok = statusCode === 200 && (body?.status === 'ok' || body?.status === undefined);
  if (!ok) {
    failed.push({
      service: serviceOrder[i] ?? ('service-' + i),
      statusCode: statusCode || 'error',
      body: typeof body === 'object' ? JSON.stringify(body) : body
    });
  }
});
const message = failed.length > 0
  ? `Gaqno Health Alert: ${failed.length} service(s) down: ${failed.map(f => f.service).join(', ')}`
  : null;
return [{ json: { failed, message, totalChecked: items.length } }];
